css:
[hidden] { display: none !important; }
.is-tab-hidden { display: none !important; }
.cookie-popup-overlay { position: fixed; bottom: 20px; left: 0px; width: 100%; display: flex; justify-content: center; z-index: 9999; padding: 0px 15px; box-sizing: border-box; }
.cookie-popup { background: rgb(255, 255, 255); width: 100%; max-width: 900px; border-radius: 8px; box-shadow: rgba(0, 0, 0, 0.15) 0px 4px 20px; padding: 20px; font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif; color: rgb(51, 51, 51); border: 1px solid rgb(224, 224, 224); }
.cookie-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px; }
.cookie-title { display: flex; align-items: center; gap: 10px; font-weight: 700; font-size: 1.1rem; }
.close-btn { background: transparent; border: none; font-size: 1.5rem; cursor: pointer; color: rgb(102, 102, 102); transition: color 0.2s; }
.close-btn:hover { color: rgb(0, 0, 0); }
.cookie-body p { margin: 0px; line-height: 1.6; color: rgb(85, 85, 85); font-size: 0.95rem; }
.cookie-footer { display: flex; justify-content: flex-end; align-items: center; gap: 20px; margin-top: 20px; }
.privacy-link { color: rgb(51, 51, 51); text-decoration: none; font-size: 0.95rem; }
.privacy-link:hover { text-decoration: underline; }
.cookie-actions { display: flex; gap: 10px; }
.btn { padding: 8px 24px; border: none; border-radius: 4px; font-weight: 600; font-size: 0.95rem; cursor: pointer; color: rgb(255, 255, 255); transition: opacity 0.2s; }
.btn-accept { background: rgb(27, 131, 84); }
.btn-accept:hover { background: rgb(22, 96, 61); }
.btn-reject { background: rgb(220, 53, 69); }
.btn-reject:hover { background: rgb(180, 35, 24); }
@media (max-width: 600px) {
  .cookie-footer { flex-direction: column; align-items: flex-start; gap: 15px; }
  .cookie-actions { width: 100%; justify-content: space-between; }
  .btn { flex: 1 1 0%; }
}
body.grayscale-mode .internal_body, body.grayscale-mode .internal_body *, body.grayscale-mode #heroCarousel, body.grayscale-mode #heroCarousel *, body.grayscale-mode section, body.grayscale-mode section *, body.grayscale-mode footer, body.grayscale-mode footer *, body.grayscale-mode .container:not(.stamp-header .container):not(.navbar .container-fluid), body.grayscale-mode .container:not(.stamp-header .container):not(.navbar .container-fluid) *, body.grayscale-mode #s4-workspace, body.grayscale-mode #s4-workspace *, body.grayscale-mode #contentRow, body.grayscale-mode #contentRow * { filter: grayscale(100%); }
body.grayscale-mode { background-color: rgb(240, 240, 240); }
.btn.grayscale-active { background-color: rgb(108, 117, 125) !important; border-color: rgb(108, 117, 125) !important; }
.logoutclass { display: none; }
